DROP TABLE IF EXISTS produccion_intervalos;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE produccion_intervalos (
  id int NOT NULL AUTO_INCREMENT,
  linea varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
  fecha date NOT NULL,
  turno tinyint NOT NULL,
  hora_inicio tinyint NOT NULL,
  modelo varchar(250) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  producto varchar(250) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  rate int DEFAULT '0',
  rate_acumulado int DEFAULT '0',
  produccion int DEFAULT '0',
  produccion_acumulada int DEFAULT '0',
  scrap int DEFAULT '0',
  delta int DEFAULT '0',
  deadtime_minutos decimal(10,2) DEFAULT '0.00',
  porcentaje_cumplimiento decimal(5,2) DEFAULT '0.00',
  justificado_minutos decimal(10,2) DEFAULT '0.00',
  tiempo_no_justificado decimal(10,2) DEFAULT '0.00',
  num_empleado_produccion int DEFAULT NULL,
  num_empleado_scrap int DEFAULT NULL,
  created_at timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (id),
  UNIQUE KEY uk_linea_fecha_turno_hora (linea,fecha,turno,hora_inicio),
  KEY idx_linea_fecha (linea,fecha),
  KEY idx_linea_turno (linea,turno),
  KEY idx_fecha_turno (fecha,turno),
  KEY idx_hora (hora_inicio)
) ENGINE=InnoDB AUTO_INCREMENT=890 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
